import React from "react";
import "./Button.css";
import axios from 'axios'
import { useQuery } from 'react-query'
import classes from "./Button.css";
import { QueryClient, QueryClientProvider } from 'react-query'

const queryClient = new QueryClient()

export default function Button() {
	return (
	  <QueryClientProvider client={queryClient}>
		<Fetcher />
	  </QueryClientProvider>
	)
  }

const Fetcher = (props) => {

	const address = 'tz1cgrzpsB43pBppH6mJzrHnFqxU8RUce991'
  	const fiat = 'USD'
	const form = React.createRef()
	const quantityRealize = React.createRef();
	const { status, data, error, isFetching } = useQuery('todos', async () => {
		const { data } = await axios.get(`http://api.portaltoblockchain.org/Analysis/Tezos/Auto?address=${address}&fiat=${fiat}`)
		return (data)
		})

	const handleMax = (e /** DOM event, click */) => {
		// prevent page from refreshing
		e.preventDefault();

		// quantityRealize is Ref
		quantityRealize.current.value =
		data.unrealizedRewardAgg.toFixed(2);
	};

	const submit = (e) => {
		props.register(e)
	}

	return(
		<div className={classes.RegisterWrapper}>
		{status === 'loading' ? (
			'Loading...'
		) : status === 'error' ? (
			error.message
		) : (
			<>
			<text>child level</text>
			<form ref = {form} className={classes.Form}>
			<input
				id = "actionForm"
				type="text"
				ref = {quantityRealize}
				placeholder='XTZ Rewards'
			/>
			<button
					onClick={handleMax}
					>
					MAX
				</button>
				<button
				onClick={() => submit()}>
					Generate Statement
				</button>
			</form>
			</>
			)}
			</div>
	)

}
